function initBurgerMenu(){document.addEventListener("DOMContentLoaded",()=>{let t=document.querySelector(".header__burger"),c=document.querySelector(".header__nav"),s=document.body,n=()=>{t.classList.remove("active"),c.classList.remove("active"),s.classList.remove("no-scroll")};t.addEventListener("click",e=>{e.stopPropagation(),t.classList.toggle("active"),c.classList.toggle("active"),t.classList.contains("active")?s.classList.add("no-scroll"):s.classList.remove("no-scroll")}),document.addEventListener("click",e=>{c.contains(e.target)||t.contains(e.target)||n()}),c.querySelectorAll("a").forEach(e=>{e.addEventListener("click",n)})})}export{initBurgerMenu};